1	/*!
2	 *  Copyright (c) 2023-2025 by Contributors
3	 * \file serve/threaded_engine.cc
4	 * \brief The implementation for threaded serving engine in MLC LLM.
5	 */
6	#include "threaded_engine.h"
7	
8	#include <tvm/ffi/extra/module.h>
9	#include <tvm/ffi/function.h>
10	#include <tvm/ffi/reflection/registry.h>
11	
12	#include <atomic>
13	#include <condition_variable>
14	#include <mutex>
15	#include <optional>
16	
17	#include "../support/json_parser.h"
18	#include "../support/module_vtable.h"
19	#include "../support/result.h"
20	#include "engine.h"
21	#include "request.h"
22	
23	namespace mlc {
24	namespace llm {
25	namespace serve {
26	
27	using tvm::Device;
28	using namespace tvm::runtime;
29	
30	/*! \brief The threaded engine instruction kind. */
31	enum class InstructionKind : int {
32	  kAddRequest = 0,
33	  kAbortRequest = 1,
34	  kUnloadEngine = 2,
35	  kReloadEngine = 3,
36	  kResetEngine = 4,
37	  kDebugCallFuncOnAllAllWorker = 5,
38	};
39	
40	/*! \brief The implementation of ThreadedEngine. */
41	class ThreadedEngineImpl : public ThreadedEngine {
42	 public:
43	  void InitThreadedEngine(Device device, Optional<Function> request_stream_callback,
44	                          Optional<EventTraceRecorder> trace_recorder) final {
45	    device_ = device;
46	    TVM_FFI_ICHECK(request_stream_callback.has_value())
47	        << "ThreadedEngine requires request stream callback function, but it is not given.";
48	    request_stream_callback_ = request_stream_callback.value();
49	    trace_recorder_ = trace_recorder;
50	  }
51	
52	  void Reload(String engine_config_json_str) final {
53	    // NOTE: important to set this before, we send out
54	    // reload instruction to the other threads
55	    // otherwise there can be deadlocks
56	    reload_finished_ = false;
57	    bool need_notify = false;
58	    {
59	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
60	      instruction_queue_.emplace_back(InstructionKind::kReloadEngine,
61	                                      std::move(engine_config_json_str));
62	      ++pending_request_operation_cnt_;
63	      need_notify = engine_waiting_;
64	    }
65	    if (need_notify) {
66	      background_loop_cv_.notify_one();
67	    }
68	    {
69	      std::unique_lock<std::mutex> lock(reload_unload_mutex_);
70	      reload_unload_cv_.wait(lock, [this] { return reload_finished_; });
71	    }
72	  }
73	
74	  void Unload() final {
75	    // NOTE: important to set this before, we send out
76	    // reload instruction to the other threads
77	    // otherwise there can be deadlocks
78	    // e.g. the other thread finish unload job and set the flag to true
79	    // then we set it back to false
80	    unload_finished_ = false;
81	    bool need_notify = false;
82	    {
83	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
84	      instruction_queue_.emplace_back(InstructionKind::kUnloadEngine, ObjectRef(nullptr));
85	      ++pending_request_operation_cnt_;
86	      need_notify = engine_waiting_;
87	    }
88	    if (need_notify) {
89	      background_loop_cv_.notify_one();
90	    }
91	    {
92	      std::unique_lock<std::mutex> lock(reload_unload_mutex_);
93	      reload_unload_cv_.wait(lock, [this] { return unload_finished_; });
94	    }
95	  }
96	
97	  void Reset() final {
98	    bool need_notify = false;
99	    {
100	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
101	      instruction_queue_.emplace_back(InstructionKind::kResetEngine, ObjectRef(nullptr));
102	      ++pending_request_operation_cnt_;
103	      need_notify = engine_waiting_;
104	    }
105	    if (need_notify) {
106	      background_loop_cv_.notify_one();
107	    }
108	  }
109	
110	  void AddRequest(Request request) final {
111	    bool need_notify = false;
112	    {
113	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
114	      instruction_queue_.emplace_back(InstructionKind::kAddRequest, request);
115	      ++pending_request_operation_cnt_;
116	      need_notify = engine_waiting_;
117	    }
118	    if (need_notify) {
119	      background_loop_cv_.notify_one();
120	    }
121	  }
122	
123	  void AbortRequest(const String& request_id) final {
124	    bool need_notify = false;
125	    {
126	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
127	      instruction_queue_.emplace_back(InstructionKind::kAbortRequest, request_id);
128	      ++pending_request_operation_cnt_;
129	      need_notify = engine_waiting_;
130	    }
131	    if (need_notify) {
132	      background_loop_cv_.notify_one();
133	    }
134	  }
135	
136	  void RunBackgroundLoop() final {
137	    // The local vectors that load the requests from critical regions.
138	    std::vector<std::pair<InstructionKind, Any>> local_instruction_queue;
139	
140	    while (!exit_now_.load(std::memory_order_relaxed)) {
141	      {
142	        std::unique_lock<std::mutex> lock(background_loop_mutex_);
143	        engine_waiting_ = true;
144	        background_loop_cv_.wait(lock, [this] {
145	          return (background_engine_ != nullptr && !background_engine_->Empty()) ||
146	                 pending_request_operation_cnt_.load() > 0 ||
147	                 exit_now_.load(std::memory_order_relaxed);
148	        });
149	        engine_waiting_ = false;
150	        local_instruction_queue = instruction_queue_;
151	        instruction_queue_.clear();
152	        pending_request_operation_cnt_ = 0;
153	      }
154	      for (const auto& [kind, arg] : local_instruction_queue) {
155	        if (kind == InstructionKind::kAddRequest) {
156	          TVM_FFI_ICHECK(background_engine_ != nullptr) << "Background engine is not loaded.";
157	          background_engine_->AddRequest(arg.as_or_throw<Request>());
158	        } else if (kind == InstructionKind::kAbortRequest) {
159	          // in a rare case, abort request can happen after unloading
160	          // aka background engine is nullptr
161	          // this happens when the on going generation was interrupted
162	          // the engine get unloaded, and then abort was called.
163	          // it is safe to ignore these abort in such case
164	          if (background_engine_ != nullptr) {
165	            background_engine_->AbortRequest(arg.as_or_throw<String>());
166	          }
167	        } else if (kind == InstructionKind::kUnloadEngine) {
168	          EngineUnloadImpl();
169	        } else if (kind == InstructionKind::kReloadEngine) {
170	          EngineUnloadImpl();
171	          EngineReloadImpl(arg.as_or_throw<String>());
172	        } else if (kind == InstructionKind::kResetEngine) {
173	          if (background_engine_ != nullptr) {
174	            background_engine_->Reset();
175	          }
176	        } else if (kind == InstructionKind::kDebugCallFuncOnAllAllWorker) {
177	          TVM_FFI_ICHECK(background_engine_ != nullptr) << "Background engine is not loaded.";
178	          Array<Any> packed_args = arg.as_or_throw<Array<Any>>();
179	          background_engine_->DebugCallFuncOnAllAllWorker(
180	              packed_args[0].as_or_throw<String>(), packed_args[1].as_or_throw<Optional<String>>());
181	        } else {
182	          LOG(FATAL) << "Cannot reach here";
183	        }
184	      }
185	      if (background_engine_ != nullptr) {
186	        background_engine_->Step();
187	      }
188	    }
189	  }
190	
191	  void RunBackgroundStreamBackLoop() final {
192	    // The local vectors that load the request stream callback inputs from critical regions.
193	    std::vector<Array<RequestStreamOutput>> local_request_stream_callback_inputs;
194	    std::vector<RequestStreamOutput> flattened_callback_inputs;
195	
196	    while (!exit_now_.load(std::memory_order_relaxed)) {
197	      {
198	        std::unique_lock<std::mutex> lock(request_stream_callback_mutex_);
199	        stream_callback_waiting_ = true;
200	        request_stream_callback_cv_.wait(lock, [this] {
201	          return pending_request_stream_callback_cnt_.load() > 0 ||
202	                 exit_now_.load(std::memory_order_relaxed);
203	        });
204	        stream_callback_waiting_ = false;
205	
206	        local_request_stream_callback_inputs = request_stream_callback_inputs_;
207	        request_stream_callback_inputs_.clear();
208	        pending_request_stream_callback_cnt_ = 0;
209	      }
210	      for (const Array<RequestStreamOutput>& callback_inputs :
211	           local_request_stream_callback_inputs) {
212	        for (const RequestStreamOutput& callback_input : callback_inputs) {
213	          flattened_callback_inputs.push_back(callback_input);
214	        }
215	      }
216	      if (!flattened_callback_inputs.empty()) {
217	        request_stream_callback_(Array<RequestStreamOutput>(flattened_callback_inputs));
218	      }
219	      flattened_callback_inputs.clear();
220	    }
221	  }
222	
223	  void ExitBackgroundLoop() final {
224	    {
225	      std::lock_guard<std::mutex> lock(background_loop_mutex_);
226	      exit_now_.store(true);
227	    }
228	    background_loop_cv_.notify_one();
229	    request_stream_callback_cv_.notify_one();
230	  }
231	
