24	  running_rsentries_changed = true;
25	  postproc_workspace = ActionPostProcessWorkspace();
26	}
27	
28	RequestState EngineStateObj::GetRequestState(Request request) {
29	  TVM_FFI_ICHECK(request->rstate != nullptr) << "The state of the request has not been defined.";
30	  return GetRef<RequestState>(static_cast<RequestStateNode*>(request->rstate));
31	}
32	
33	const std::vector<RequestStateEntry>& EngineStateObj::GetRunningRequestStateEntries() {
34	  if (running_rsentries_changed) {
35	    cached_running_rsentries_.clear();
36	    for (const Request& request : running_queue) {
37	      for (const RequestStateEntry& rsentry : GetRequestState(request)->entries) {
38	        // One request entry is considered as running for decode if it is a leaf and has
39	        // finished all input prefill.
40	        if (rsentry->status == RequestStateStatus::kAlive && rsentry->child_indices.empty() &&
41	            rsentry->mstates[0]->inputs.empty()) {
42	          cached_running_rsentries_.push_back(rsentry);
43	        }
44	      }
45	    }
46	    running_rsentries_changed = false;
47	  }
48	  return cached_running_rsentries_;
49	  //
50	}
51	
52	}  // namespace serve
53	}  // namespace llm
54	}  // namespace mlc
