88	void StreamBackErrorImpl(Request request, FRequestStreamCallback request_stream_callback,
89	                         String finish_reason) {
90	  // If the request input length exceeds the maximum allowed single sequence length,
91	  // invoke callback and do not process the request.
92	  Array<RequestStreamOutput> output{RequestStreamOutput(
93	      request->id, std::vector<std::vector<int64_t>>(request->generation_cfg->n), std::nullopt,
94	      std::vector<Optional<String>>(request->generation_cfg->n, finish_reason),
95	      std::vector<String>(request->generation_cfg->n))};
96	  // NOTE: Invariant requirement
97	  // always stream back final usage
98	  // otherwise frontend may have issues deciding
99	  String dummy_usage = ("{ \"prompt_tokens\": 0, \"completion_tokens\": 0, \"total_tokens\": 0 }");
100	  output.push_back(RequestStreamOutput::Usage(request->id, dummy_usage));
101	  if (request_stream_callback != nullptr) {
102	    request_stream_callback(output);
103	  }
104	}
