668	  void AddRequest(Request request) final {
669	    NVTXScopedRange nvtx_scope("Add request " + request->id);
670	    // special requests do not involve generation
671	    if (request->generation_cfg->debug_config.special_request != SpecialRequestKind::kNone) {
672	      this->HandleSpecialRequests(request);
673	      return;
674	    }
675	
676	    RECORD_EVENT(trace_recorder_, request->id, "request added to engine");
677	    auto add_time_point = std::chrono::high_resolution_clock::now();
678	
679	    // Get a request copy where all text inputs are tokenized.
680	    request = Request::FromUntokenized(request, tokenizer_);
681	    TVM_FFI_ICHECK_NE(request->prompt_tokens, -1);
682	
683	    if (request->prompt_tokens >= engine_config_->max_single_sequence_length &&
684	        estate_->request_stream_callback_ != nullptr) {
685	      this->StreamBackError(request, "length");
686	      return;
687	    }
688	
689	    // Handle disaggregation requests.
690	    if (request->generation_cfg->debug_config.disagg_config.kind != DisaggRequestKind::kNone) {
691	      bool return_now = this->HandleDisaggRequest(request);
692	      if (return_now) {
693	        return;
694	      }
695	    }
696	
697	    // Append to the waiting queue and create the request state.
698	    estate_->waiting_queue.push_back(request);
699	
700	    int n = request->generation_cfg->n;
701	    int rng_seed = request->generation_cfg->seed;
702	    auto compiled_grammar = GetGrammarFromResponseFormat(request->generation_cfg->response_format);
703	
704	    std::vector<RequestStateEntry> rsentries;
705	    // Create the request state entry for the input.
706	    rsentries.emplace_back(request, models_.size(), estate_->id_manager.GetNewId(), rng_seed,
707	                           token_table_, compiled_grammar);
708	    if (n > 1) {
709	      // Then create a request state entry for each parallel generation branch.
710	      // We add a offset to the rng seed so that to make generations different.
711	      rsentries.reserve(n + 1);
712	      rsentries[0]->child_indices.reserve(n);
713	      for (int i = 0; i < n; ++i) {
714	        rsentries[0]->child_indices.push_back(rsentries.size());
715	        rsentries.emplace_back(request, models_.size(), estate_->id_manager.GetNewId(),
716	                               rng_seed + i + 1, token_table_, compiled_grammar,
717	                               /*parent_idx=*/0);
718	      }
719	    }
720	    RequestState rstate = RequestState(std::move(rsentries), n, add_time_point);
721	    for (const RequestStateEntry& rsentry : rstate->entries) {
722	      // Set the back reference.
723	      // note, we avoid cyclic reference and use raw ptr.
724	      rsentry->rstate = rstate.operator->();
725	    }
726	    request->rstate = rstate.operator->();
727	    estate_->request_states.emplace(request->id, rstate);
728	  }
