734	  void AbortAllRequests() final {
735	    // - Collect all the request ids.
736	    std::vector<String> request_ids;
737	    request_ids.reserve(estate_->request_states.size());
738	    for (const auto& kv : estate_->request_states) {
739	      request_ids.push_back(kv.first);
740	    }
741	    // - Abort all the requests.
742	    for (const String& request_id : request_ids) {
743	      AbortRequest(request_id);
744	    }
745	  }
