771	  /************** Utility Functions **************/
772	  std::tuple<Optional<Session>, int, std::vector<int>> CreateDiscoSession(
773	      const std::vector<std::string>& model_libs,
774	      const std::vector<tvm::ffi::json::Object>& model_configs, Device device) {
775	    const auto& base_model_config = model_configs[0];
776	
777	    auto f_get_num_shards_num_stages =
778	        [&device](const std::string& model_lib,
779	                  const tvm::ffi::json::Object& model_config) -> std::pair<int, int> {
780	      if (!StartsWith(model_lib, "system://")) {
781	        Module executable = ffi::Module::LoadFromFile(model_lib);
782	        Optional<Function> fload_exec = executable->GetFunction("vm_load_executable");
783	        TVM_FFI_ICHECK(fload_exec.has_value()) << "TVM runtime cannot find vm_load_executable";
784	        Module local_vm = fload_exec.value()().cast<Module>();
785	        local_vm->GetFunction("vm_initialization")
786	            .value()(static_cast<int>(device.device_type), device.device_id,
787	                     static_cast<int>(tvm::runtime::memory::AllocatorType::kPooled),
788	                     static_cast<int>(kDLCPU), 0,
789	                     static_cast<int>(tvm::runtime::memory::AllocatorType::kPooled));
790	        ModelMetadata metadata = ModelMetadata::FromModule(local_vm, std::move(model_config));
791	        return {metadata.tensor_parallel_shards, metadata.pipeline_parallel_stages};
792	      } else {
793	        return {1, 1};
794	      }
795	    };
796	
797	    int num_shards = -1;
798	    int max_num_stages = 1;
799	    std::vector<int> model_num_pipeline_stages;
800	    model_num_pipeline_stages.reserve(model_libs.size());
801	    TVM_FFI_ICHECK_EQ(model_libs.size(), model_configs.size());
802	    for (int i = 0; i < static_cast<int>(model_libs.size()); ++i) {
803	      auto [model_num_shards, model_num_stages] =
804	          f_get_num_shards_num_stages(model_libs[i], model_configs[i]);
805	      model_num_pipeline_stages.push_back(model_num_stages);
806	      max_num_stages = std::max(max_num_stages, model_num_stages);
807	      if (i == 0) {
808	        num_shards = model_num_shards;
809	      } else {
810	        TVM_FFI_ICHECK_EQ(model_num_shards, num_shards)
811	            << "Inconsistent tensor_parallel_shards values across models. Some model is compiled "
812	               "with tensor_parallel_shards "
813	            << num_shards << " and some other model is compiled with tensor_parallel_shards "
814	            << model_num_shards;
815	      }
816	    }
817	
818	    Optional<Session> session = std::nullopt;
819	    int num_workers = num_shards * max_num_stages;
820	    if (num_workers > 1) {
821	#ifndef MLC_SINGLE_GPU_ONLY
822	      constexpr const char* f_create_process_pool = "runtime.disco.create_process_pool";
823	      if (!Function::GetGlobal(f_create_process_pool).has_value()) {
824	        LOG(FATAL) << "Cannot find process launcher `" << f_create_process_pool << "`. "
825	                   << "Multi-GPU inference depends on MLC LLM Python API to launch process.";
826	      }
827	      std::string ccl;
828	      if (device.device_type == kDLCUDA) {
829	        ccl = "nccl";
830	      } else if (device.device_type == kDLROCM) {
831	        ccl = "rccl";
832	      } else {
833	        LOG(FATAL) << "ValueError: Multi-GPU on device " << DLDeviceType2Str(device.device_type)
834	                   << " is not supported. Currently, only NCCL and RCCL are integrated.";
835	      }
836	      std::vector<int64_t> device_ids(num_workers);
837	      for (int i = 0; i < num_workers; ++i) {
838	        // device.device_id is the start of the worker 0 of this model
839	        device_ids[i] = device.device_id + i;
840	      }
841	      const std::string& green_text_begin = "\033[92m";
842	      const std::string& yellow_text_begin = "\033[93m";
843	      const std::string& colored_text_end = "\033[0m";
844	      auto [socket_host, socket_port] = GetEnvSocketHostPort();
845	      if (max_num_stages > 1 && socket_host.has_value()) {
846	        // Use SocketSession when pipeline parallelism enabled and socket host and port are set.
847	        TVM_FFI_ICHECK_GT(socket_port, 0)
848	            << "Invalid MLC socket port " << socket_port
849	            << ". Please set a valid port value in environment variable \"MLC_SOCKET_PORT\".";
850	        LOG(INFO) << "Creating MLC socket session with socket host " << socket_host.value()
851	                  << " and port " << socket_port;
852	        LOG(INFO) << "Please launch " << green_text_begin << max_num_stages - 1 << colored_text_end
853	                  << " remote socket node(s) with the following command to proceed:\n\t"
854	                  << green_text_begin << "python -m mlc_llm.cli.disco_remote_socket_session "
855	                  << (socket_host.value() == "0.0.0.0" ? "<YOUR_NODE_IP>" : socket_host.value())
856	                  << " " << socket_port << " " << num_shards << colored_text_end;
857	        static Function f_create_socket_sess =
858	            Function::GetGlobalRequired("runtime.disco.SocketSession");
859	        Session sess =
860	            f_create_socket_sess(max_num_stages, num_shards, /*num_groups=*/max_num_stages,
861	                                 socket_host.value(), socket_port)
862	                .cast<Session>();
863	        session = std::move(sess);
864	      } else {
865	        if (max_num_stages > 1) {
866	          LOG(INFO)
867	              << yellow_text_begin
868	              << "Model is enabled with \"pipeline_parallel_stages\" but the socket host/port is "
869	                 "not set. If you intend to run the model on multiple nodes, please set "
870	                 "environment variable \"MLC_SOCKET_HOST\" and \"MLC_SOCKET_PORT\" and run again."
871	              << colored_text_end;
872	        }
873	        // Use ProcessSession otherwise.
874	        session = Session::ProcessSession(num_workers, max_num_stages, f_create_process_pool,
875	                                          "mlc_llm.cli.worker");
876	      }
877	      session.value()->InitCCL(ccl, Shape(device_ids));
878	#else
879	      LOG(FATAL) << "MLC_SINGLE_GPU_ONLY is specified. Multi-GPU is not enabled.";
880	#endif  // MLC_SINGLE_GPU_ONLY
881	    }
882	    return {session, num_shards, model_num_pipeline_stages};
883	  }
